/**
 * Run after a short lv_timer delay (same pattern as Home refresh) so the busy overlay is
 * flushed to the panel before rm_app_backend_* blocks the LVGL task.
 */
static void ui_login_backend_timer_cb(lv_timer_t *t)
{
    if (t) {
        lv_timer_del(t);
    }

    const char *err_reason = NULL;

    esp_err_t ret = rm_app_backend_init();
    if (ret != ESP_OK) {
        ui_hide_busy();
        ui_show_msgbox(ui_str(UI_STR_MSGBOX_ERROR), ui_str(UI_STR_FAILED_INIT_RM));
        return;
    }

    bool ok = rm_app_backend_login(s_login_email_buf, s_login_password_buf, &err_reason);
    ui_hide_busy();

    if (ok) {
        if (ui_Screen_Home) {
            ui_Screen_Home_refresh_from_backend();
            lv_disp_load_scr(ui_Screen_Home);
        }
        return;
    }

    ui_show_msgbox(ui_str_by_id(UI_STR_MSGBOX_ERROR), err_reason);
    free((char *)err_reason);
}

