static void ui_login_adjust_for_keyboard(lv_obj_t *ta, lv_obj_t *kb)
{
    if (ta == NULL || kb == NULL) {
        return;
    }

    /* Ensure the keyboard is laid out at the bottom before querying coordinates */
    lv_obj_update_layout(kb);
    lv_obj_update_layout(ta);

    lv_area_t kb_a;
    lv_area_t ta_a;
    lv_obj_get_coords(kb, &kb_a);
    lv_obj_get_coords(ta, &ta_a);

    /* If textarea bottom is below keyboard top, shift UI up */
    const int32_t margin = 8;
    int32_t overlap = ta_a.y2 - (kb_a.y1 - margin);
    if (overlap < 0) {
        overlap = 0;
    }

    /* Avoid shifting too much (cap to screen height) */
    lv_disp_t *disp = lv_disp_get_default();
    int32_t max_shift = 120;
    if (disp) {
        max_shift = lv_disp_get_ver_res(disp);
    }
    if (overlap > max_shift) {
        overlap = max_shift;
    }

    ui_login_set_shift_y(overlap);
}

